import { LitElement, html, unsafeCSS } from 'lit';
import { customElement, property, state } from 'lit/decorators.js';
import popupStyles from '../styles/ComboBoxPopup.css';

export interface ComboBoxPopupOption {
    text: string;
    value: unknown;
    selected: boolean;
    originalItem: unknown;
}

@customElement('umi-combobox-popup')
export class ComboBoxPopup extends LitElement {
    @property({ attribute: false }) optionsWithSelection: ComboBoxPopupOption[] = [];
    @property({ type: Boolean, reflect: true }) opened = false;
    @property({ type: Number, attribute: 'max-visible-items' }) maxVisibleItems = 6;

    @state() private _hoveredIndex = -1;

    static styles = unsafeCSS(popupStyles);

    connectedCallback(): void {
        super.connectedCallback();
        document.addEventListener('mousedown', this._onDocumentMouseDown, true);
        document.addEventListener('keydown', this._onDocumentKeyDown, true);
    }

    disconnectedCallback(): void {
        super.disconnectedCallback();
        document.removeEventListener('mousedown', this._onDocumentMouseDown, true);
        document.removeEventListener('keydown', this._onDocumentKeyDown, true);
    }

    open(): void {
        this.opened = true;
    }

    close(): void {
        if (!this.opened) return;
        this.opened = false;
        this.dispatchEvent(new CustomEvent('closed', { bubbles: true, composed: true }));
    }

    private _emitOptionSelected(index: number, text: string): void {
        this.dispatchEvent(new CustomEvent('option-selected', {
            detail: { index, text },
            bubbles: true,
            composed: true,
        }));
    }

    private _onDocumentMouseDown = (event: MouseEvent): void => {
        if (!this.opened) return;
        const path = event.composedPath();
        if (path.includes(this)) return;
        this.close();
    };

    private _onDocumentKeyDown = (event: KeyboardEvent): void => {
        if (!this.opened) return;
        if (event.key === 'Escape') {
            event.preventDefault();
            this.close();
        }
    };

    private _onOptionClick(index: number, option: ComboBoxPopupOption): void {
        this._emitOptionSelected(index, option.text ?? '');
        this.close();
    }

    render() {
        const itemHeight = 48;
        const contentHeight = Math.min(this.maxVisibleItems, this.optionsWithSelection.length) * itemHeight;

        return html`
            <div class="popup ${this.opened ? 'opened' : ''}" style="--popup-max-height:${Math.max(100, contentHeight + 16)}px">
                ${this.optionsWithSelection.length === 0
                    ? html`<div class="empty">Нет доступных опций</div>`
                    : html`
                        <div class="list" role="listbox">
                            ${this.optionsWithSelection.map((option, index) => html`
                                <button
                                    class="option ${option.selected ? 'selected' : ''} ${this._hoveredIndex === index ? 'hovered' : ''}"
                                    style="--i:${index};"
                                    @mouseenter=${() => { this._hoveredIndex = index; }}
                                    @mouseleave=${() => { this._hoveredIndex = -1; }}
                                    @click=${() => this._onOptionClick(index, option)}
                                    role="option"
                                    aria-selected=${option.selected ? 'true' : 'false'}
                                >
                                    <span class="text">${option.text ?? ''}</span>
                                    ${option.selected ? html`<span class="check">check</span>` : null}
                                </button>
                            `)}
                        </div>
                    `}
            </div>
        `;
    }
}

declare global {
    interface HTMLElementTagNameMap {
        'umi-combobox-popup': ComboBoxPopup;
    }
}
