import { LitElement, html, unsafeCSS } from 'lit';
import { customElement, property, state } from 'lit/decorators.js';
import comboStyles from '../styles/ComboBox.css';
import './ComboBoxPopup.js';
import type { ComboBoxPopup, ComboBoxPopupOption } from './ComboBoxPopup.js';

type ModelLike = unknown[] | { count: number; get(index: number): unknown };

type SelectedItem = {
    index: number;
    originalItem: unknown;
    text: string;
    value: unknown;
    modelType: 'ListModel' | 'Array';
    totalItems: number;
};

@customElement('umi-combobox')
export class ComboBox extends LitElement {
    @property({ attribute: false }) model: ModelLike = [];
    @property({ type: String, attribute: 'text-role' }) textRole = '';
    @property({ type: String, attribute: 'value-role' }) valueRole = '';

    @property({ type: String, attribute: 'label-text' }) labelText = '';
    @property({ type: String, attribute: 'supporting-text' }) supportingText = '';
    @property({ type: String }) prefix = '';
    @property({ type: String }) suffix = '';
    @property({ type: String, attribute: 'error-text' }) errorText = '';

    @property({ type: String, attribute: 'trailing-icon-name' }) trailingIconName = 'arrow_drop_down';
    @property({ type: String, attribute: 'leading-icon-name' }) leadingIconName = 'search';
    @property({ type: Boolean, attribute: 'has-leading-icon' }) hasLeadingIcon = false;
    @property({ type: Boolean, attribute: 'has-trailing-icon' }) hasTrailingIcon = true;

    @property({ type: Boolean }) filled = true;
    @property({ type: Boolean, attribute: 'has-error' }) hasError = false;
    @property({ type: Number, attribute: 'scale-font' }) scaleFont = 1;
    @property({ type: Boolean, attribute: 'auto-select-first-element' }) autoSelectFirstElement = false;

    @property({ type: Boolean, attribute: 'enable-leading-icon-custom-click' }) enableLeadingIconCustomClick = false;
    @property({ type: String, attribute: 'leading-icon-tooltip-text' }) leadingIconTooltipText = 'Поиск';
    @property({ type: Boolean, attribute: 'leading-icon-enabled' }) leadingIconEnabled = true;

    @property({ type: Number, attribute: 'custom-width' }) customWidth = -1;
    @property({ type: Number, attribute: 'custom-height' }) customHeight = -1;
    @property({ type: Number, attribute: 'scale-ratio' }) scaleRatio = 1;

    @property({ type: Number, attribute: 'current-index' }) currentIndex = -1;
    @property({ type: String, attribute: 'current-text' }) currentText = '';

    @property({ type: Boolean, reflect: true }) disabled = false;

    @state() private _isFocused = false;
    @state() private _isHovered = false;
    @state() private _isPressed = false;
    @state() private _isOpen = false;
    @state() private _optionsWithSelection: ComboBoxPopupOption[] = [];
    @state() private _dynamicRadius = 12;
    @state() private _livingScale = 1;

    static styles = unsafeCSS(comboStyles);

    updated(changedProperties: Map<string, unknown>): void {
        if (changedProperties.has('model') && this.autoSelectFirstElement) {
            this.selectFirstElement();
        }
        if (changedProperties.has('autoSelectFirstElement') && this.autoSelectFirstElement) {
            this.selectFirstElement();
        }
    }

    firstUpdated(): void {
        this._syncLivingMetrics();
        if (this.autoSelectFirstElement) {
            this.selectFirstElement();
        }
    }

    private _baseRadius(): number {
        const h = this.customHeight > 0 ? this.customHeight : 56;
        return Math.max(4, Math.min(16, Math.round(h / 4)));
    }

    private _syncLivingMetrics(): void {
        this._dynamicRadius = this._baseRadius();
        this._livingScale = 1;
    }

    clearFocus(): void {
        this._isFocused = false;
        this._emitSignal('comboFocusChanged', false);
        this._emitSignal('resetFocus');
    }

    setElement(index: number): void {
        const itemCount = this._getItemCount();
        if (index >= 0 && index < itemCount) {
            const item = this._getRawItem(index);
            this.currentIndex = index;
            this.currentText = this.getItemText(item, index);
        } else {
            this.currentIndex = -1;
            this.currentText = '';
        }
    }

    selectFirstElement(): void {
        this.setElement(0);
    }

    getItemText(item: unknown, _index: number): string {
        if (typeof item === 'string') return item;
        if (typeof item === 'object' && item !== null) {
            const row = item as Record<string, unknown>;
            if (this.textRole && row[this.textRole] !== undefined) return String(row[this.textRole]);
            if (row.text !== undefined) return String(row.text);
            if (row.name !== undefined) return String(row.name);
            if (row.title !== undefined) return String(row.title);
        }
        return String(item ?? '');
    }

    getItemValue(item: unknown, _index: number): unknown {
        if (typeof item === 'string') return item;
        if (typeof item === 'object' && item !== null) {
            const row = item as Record<string, unknown>;
            if (this.valueRole && row[this.valueRole] !== undefined) return row[this.valueRole];
            if (row.value !== undefined) return row.value;
            if (row.code !== undefined) return row.code;
            if (row.id !== undefined) return row.id;
        }
        return item;
    }

    createOptionsWithSelection(): ComboBoxPopupOption[] {
        const result: ComboBoxPopupOption[] = [];
        const itemCount = this._getItemCount();
        for (let i = 0; i < itemCount; i++) {
            const item = this._getRawItem(i);
            result.push({
                text: this.getItemText(item, i),
                value: this.getItemValue(item, i),
                selected: i === this.currentIndex,
                originalItem: item,
            });
        }
        return result;
    }

    getCurrentSelectedItem(): SelectedItem | null {
        const itemCount = this._getItemCount();
        if (this.currentIndex < 0 || this.currentIndex >= itemCount) return null;
        const item = this._getRawItem(this.currentIndex);
        return {
            index: this.currentIndex,
            originalItem: item,
            text: this.getItemText(item, this.currentIndex),
            value: this.getItemValue(item, this.currentIndex),
            modelType: this._isListModel(this.model) ? 'ListModel' : 'Array',
            totalItems: itemCount,
        };
    }

    hasSelectedItem(): boolean {
        const itemCount = this._getItemCount();
        return this.currentIndex >= 0 && this.currentIndex < itemCount;
    }

    getItemByIndex(index: number): Omit<SelectedItem, 'modelType' | 'totalItems'> | null {
        const itemCount = this._getItemCount();
        if (index < 0 || index >= itemCount) return null;
        const item = this._getRawItem(index);
        return {
            index,
            originalItem: item,
            text: this.getItemText(item, index),
            value: this.getItemValue(item, index),
        };
    }

    setLeadingIconEnabled(enabled: boolean): void { this.leadingIconEnabled = enabled; }
    setLeadingIconSource(source: string): void { this.leadingIconName = source; }
    setLeadingIconTooltip(tooltip: string): void { this.leadingIconTooltipText = tooltip; }
    enableCustomLeadingIconClick(enable: boolean): void { this.enableLeadingIconCustomClick = enable; }
    toggleLeadingIcon(): void { this.hasLeadingIcon = !this.hasLeadingIcon; }

    simulateLeadingIconClick(): void {
        if (this.hasLeadingIcon && this.leadingIconEnabled && !this.disabled) {
            this._emitSignal('leadingIconClicked');
            if (!this.enableLeadingIconCustomClick) {
                this._emitSignal('searchClicked');
            }
        }
    }

    private _isListModel(value: ModelLike): value is { count: number; get(index: number): unknown } {
        return typeof value === 'object' && value !== null && 'count' in value && 'get' in value;
    }

    private _getItemCount(): number {
        if (!this.model) return 0;
        if (this._isListModel(this.model)) return this.model.count;
        if (Array.isArray(this.model)) return this.model.length;
        return 0;
    }

    private _getRawItem(index: number): unknown {
        if (this._isListModel(this.model)) return this.model.get(index);
        if (Array.isArray(this.model)) return this.model[index];
        return null;
    }

    private _openPopup(): void {
        if (this.disabled) return;
        this._isOpen = true;
        this._isFocused = true;
        this._livingScale = 1.01;
        this._emitSignal('comboFocusChanged', true);
        this._optionsWithSelection = this.createOptionsWithSelection();
        this._popupEl?.open();
    }

    private _closePopup(): void {
        this._isOpen = false;
        this._livingScale = this._isHovered ? 1.01 : 1;
        this._popupEl?.close();
    }

    private _onLeadingIconClick(event: MouseEvent): void {
        event.stopPropagation();
        if (this.disabled || !this.leadingIconEnabled) return;
        this._emitSignal('leadingIconClicked');
        if (!this.enableLeadingIconCustomClick) {
            this._emitSignal('searchClicked');
        }
    }

    private _onTrailingIconClick(event: MouseEvent): void {
        event.stopPropagation();
        if (this._isOpen) {
            this._closePopup();
        } else {
            this._openPopup();
        }
    }

    private _onRootClick(): void {
        if (this.disabled) return;
        this._openPopup();
    }

    private _onPopupClosed(): void {
        this._isOpen = false;
        this._livingScale = this._isHovered ? 1.01 : 1;
        this.clearFocus();
    }

    private _onOptionSelected(e: CustomEvent<{ index: number; text: string }>): void {
        const { index } = e.detail;
        const item = this._getRawItem(index);
        this.currentIndex = index;
        this.currentText = this.getItemText(item, index);

        this._emitSignal('optionSelected', { index, text: this.currentText });
        this._emitSignal('itemSelected', { index, item });
        this._closePopup();
    }

    private _onKeyDown(event: KeyboardEvent): void {
        if (event.key === 'Escape') {
            if (this._isOpen) {
                this._closePopup();
            } else {
                this.clearFocus();
            }
            event.preventDefault();
        }

        if ((event.key === 'Enter' || event.key === ' ') && !this._isOpen) {
            this._openPopup();
            event.preventDefault();
        }
    }

    private _emitSignal(name: string, detail?: unknown): void {
        this.dispatchEvent(new CustomEvent(name, { detail, bubbles: true, composed: true }));
        const kebab = name.replace(/([a-z])([A-Z])/g, '$1-$2').toLowerCase();
        if (kebab !== name) {
            this.dispatchEvent(new CustomEvent(kebab, { detail, bubbles: true, composed: true }));
        }
    }

    private get _popupEl(): ComboBoxPopup | null {
        return this.renderRoot?.querySelector('umi-combobox-popup') ?? null;
    }

    render() {
        const showFloatingLabel = this.labelText !== '' && (this.currentText !== '' || this._isFocused);
        const hasValue = this.currentText !== '';

        return html`
            <div
                class="root ${this.filled ? 'filled' : 'outlined'} ${this.hasError ? 'error' : ''} ${this._isFocused ? 'focused' : ''} ${this._isHovered ? 'hovered' : ''} ${this.disabled ? 'disabled' : ''}"
                tabindex=${this.disabled ? -1 : 0}
                @mouseenter=${() => {
                    this._isHovered = true;
                    this._dynamicRadius = this._baseRadius() + 2;
                    this._livingScale = 1.01;
                }}
                @mouseleave=${() => {
                    this._isHovered = false;
                    this._isPressed = false;
                    this._dynamicRadius = this._baseRadius();
                    this._livingScale = this._isOpen ? 1.01 : 1;
                }}
                @mousedown=${() => {
                    this._isPressed = true;
                    this._livingScale = 0.985;
                }}
                @mouseup=${() => {
                    this._isPressed = false;
                    this._livingScale = this._isHovered || this._isOpen ? 1.01 : 1;
                }}
                @focus=${() => { this._isFocused = true; this._emitSignal('comboFocusChanged', true); }}
                @blur=${() => { if (!this._isOpen) this.clearFocus(); }}
                @keydown=${this._onKeyDown}
                @click=${this._onRootClick}
                style="
                    --cb-width:${this.customWidth > 0 ? `${this.customWidth}px` : '100%'};
                    --cb-height:${this.customHeight > 0 ? `${this.customHeight}px` : '56px'};
                    --cb-font-scale:${Math.max(0.5, this.scaleFont)};
                    --cb-ui-scale:${Math.max(0.75, this.scaleRatio || 1)};
                    --cb-radius-dynamic:${this._dynamicRadius}px;
                    --cb-living-scale:${this._livingScale};
                "
                role="combobox"
                aria-expanded=${this._isOpen ? 'true' : 'false'}
                aria-haspopup="listbox"
            >
                <div class="container">
                    <div class="state-layer" aria-hidden="true"></div>
                    <div class="active-indicator" aria-hidden="true"></div>
                    ${this.hasLeadingIcon
                        ? html`
                            <button
                                class="icon leading ${this.leadingIconEnabled ? '' : 'icon-disabled'}"
                                type="button"
                                title=${this.leadingIconTooltipText}
                                ?disabled=${this.disabled || !this.leadingIconEnabled}
                                @click=${this._onLeadingIconClick}
                            >
                                ${this.leadingIconName}
                            </button>
                        `
                        : null}

                    <div class="content ${showFloatingLabel ? 'floating' : ''}">
                        ${this.labelText
                            ? html`<div class="label ${showFloatingLabel ? 'small' : ''}">${this.labelText}</div>`
                            : null}

                        <div class="value-row">
                            ${this.prefix && hasValue ? html`<span class="affix">${this.prefix}</span>` : null}
                            <span class="value ${hasValue ? '' : 'placeholder'}">${this.currentText || ''}</span>
                            ${this.suffix && hasValue ? html`<span class="affix">${this.suffix}</span>` : null}
                        </div>
                    </div>

                    ${this.hasTrailingIcon
                        ? html`
                            <button class="icon trailing ${this._isOpen ? 'open' : ''}" type="button" @click=${this._onTrailingIconClick}>
                                ${this.trailingIconName}
                            </button>
                        `
                        : null}
                </div>

                ${this.supportingText
                    ? html`<div class="supporting ${this.hasError ? 'error' : ''}">${this.supportingText}</div>`
                    : null}

                <umi-combobox-popup
                    .optionsWithSelection=${this._optionsWithSelection}
                    .opened=${this._isOpen}
                    @closed=${this._onPopupClosed}
                    @option-selected=${this._onOptionSelected}
                ></umi-combobox-popup>
            </div>
        `;
    }
}

declare global {
    interface HTMLElementTagNameMap {
        'umi-combobox': ComboBox;
    }
}
